// src/qdrant/filters/glob.ts
import picomatch from 'picomatch';

/**
 * Creates a matcher function for glob pattern
 */
export function createGlobMatcher(pattern: string): (path: string) => boolean {
  return picomatch(pattern, { bash: true });
}

/**
 * Filters search results by glob pattern on relativePath
 * Used for post-filtering Qdrant results when glob not supported natively
 */
export function filterResultsByGlob<T extends { payload?: { relativePath?: string } }>(
  results: T[],
  pattern: string,
): T[] {
  const isMatch = createGlobMatcher(pattern);
  return results.filter(item => {
    const path = item.payload?.relativePath;
    return path && isMatch(path);
  });
}

// src/qdrant/filters/index.ts
export { createGlobMatcher, filterResultsByGlob } from './glob.js';
```

